import React, { useEffect, useState } from "react";

function Fields() {

  const [fields, setFields] = useState([]);

  useEffect(() => {
    fetch("http://localhost:3000/fields")
      .then(res => res.json())
      .then(data => setFields(data));
  }, []);

  return (

    <div>

      <h1>Football Fields</h1>

      <table border="1">

        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Location</th>
            <th>Price</th>
          </tr>
        </thead>

        <tbody>

          {fields.map(field => (
            <tr key={field.id}>
              <td>{field.id}</td>
              <td>{field.name}</td>
              <td>{field.location}</td>
              <td>{field.price}</td>
            </tr>
          ))}

        </tbody>

      </table>

    </div>

  );
}

export default Fields;
